    // for the next element to be considered a fixed point.
    let k = 0; 

    for (let i = 0; i < nums.length; i++) {
        const Ni = nums[i];

        // For nums[i] to become the (k+1)-th fixed point (meaning it lands at index k+F, 
        // where k is the count of previous fixed points, and F is fillers), 
        // we require its value Ni to equal its final index.

        // 1. Lower bound check: Ni must be at least k. 
        // (If Ni < k, then even with zero fillers (F=0), the resulting index k+F > Ni.
        // Since we require Ni = k+F, Ni must be >= k).

        // 2. Upper bound check: Ni must be at most i.
        // (Since we have only i elements in the prefix nums[0...i-1] available, 
        // and k elements are already chosen as fixed points, there are i-k slots available 
        // for fillers. The required fillers F = Ni - k must be <= i - k. 
        // Ni - k <= i - k => Ni <= i).

        if (Ni >= k && Ni <= i) {
            // If the condition is met, we greedily select nums[i] as the next fixed point,
            // increasing the achievable count k.
            k++;
        }
    }

    return k;
}

